   148→  /** Binding policy for call-by-value. */
   149→  static final BindingPolicy CALL_BY_VALUE = new BindingPolicy() {
   150→    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) { return new ValueBinding(var, arg.accept(ev)); }
   151→    public Binding newDummyBinding(Variable var) { return new ValueBinding(var, null); } // null indicates still unbound
   152→  };
