    22→/** A Jam integer constant, also used to represent an integer token for parsing.  */
    23→class IntConstant implements Token, Constant, JamVal {
    24→  private int value;
    25→  
    26→  IntConstant(int i) { value = i; }
    27→  // duplicates can occur!
    28→  
    29→  public int value() { return value; }
    30→  
    31→  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forIntConstant(this); }
    32→  public <ResType> ResType accept(JamValVisitor<ResType> v) { return v.forIntConstant(this); }
    33→  /** redefines equals so that equal integers are recognized as equal */
    34→  public boolean equals(Object other) {
    35→    return (other != null && this.getClass() == other.getClass()) && 
    36→      (value == ((IntConstant)other).value());
    37→  }
    38→  /** computes the obvious hashcode for this consistent with equals. */
    39→  public int hashcode() { return value; }
    40→  public String toString() { return String.valueOf(value); }
    41→}
