/** Class for a lazy cons structure that uses call-by-name evaluation (re-evaluates each access). */
static class JamLazyNameCons extends JamCons {
  /** Suspension for first */
  protected Suspension firstSusp;
  /** Suspension for rest */
  protected Suspension restSusp;

  public JamLazyNameCons(Suspension f, Suspension r) {
    super(null, null);
    firstSusp = f;
    restSusp = r;
  }

  /** Evaluates and returns the first element (re-evaluated each call for call-by-name). */
  @Override
  public JamVal first() { return firstSusp.eval(); }

  /** Evaluates and returns the rest element as a JamList (re-evaluated each call for call-by-name). */
  @Override
  public JamList rest() { return JamCons.checkList(restSusp.eval()); }
}

/** Class for a lazy cons with call-by-need optimization (caches evaluated values). */
static class JamLazyNeedCons extends JamLazyNameCons {
  /** Cached value of first; null means not yet forced. */
  private JamVal firstVal = null;
  /** Whether first has been forced. */
  private boolean firstForced = false;
  /** Cached value of rest; null means not yet forced. */
  private JamList restVal = null;
  /** Whether rest has been forced. */
  private boolean restForced = false;

  public JamLazyNeedCons(Suspension f, Suspension r) {
    super(f, r);
  }

  /** Returns the first element, evaluating and caching it on first access. */
  @Override
  public JamVal first() {
    if (!firstForced) {
      firstVal = firstSusp.eval();
      firstForced = true;
    }
    return firstVal;
  }

  /** Returns the rest element as a JamList, evaluating and caching it on first access. */
  @Override
  public JamList rest() {
    if (!restForced) {
      restVal = JamCons.checkList(restSusp.eval());
      restForced = true;
    }
    return restVal;
  }
}

