/** Implements recursive let: each RHS is evaluated in an environment that includes all bindings. */
public JamVal forLet(Let l) {

  /* Extract binding vars and exps (rhs's) from l */
  Variable[] vars = l.vars();
  AST[] exps = l.exps();
  int n = vars.length;

  /* Create dummy bindings (initially unbound) and build the recursive environment. */
  Binding[] bindings = new Binding[n];
  PureList<Binding> newEnv = env();
  for (int i = 0; i < n; i++) {
    bindings[i] = bindingPolicy.newDummyBinding(vars[i]);
    newEnv = newEnv.cons(bindings[i]);
  }

  /* Create new EvalVisitor with the recursive environment. */
  EvalVisitor newEV = newEvalVisitor(newEnv);

  /* Set each binding to its RHS evaluated in the recursive environment. */
  for (int i = 0; i < n; i++) {
    bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));
  }

  return l.body().accept(newEV);
}

