/** Short-circuit structural equality for Jam values; handles lazy lists without diverging on identical objects. */
private boolean jamValEquals(JamVal v1, JamVal v2) {
  if (v1 == v2) return true;  // short-circuit on identical objects (handles cyclic/infinite lists)
  if (v1 instanceof JamCons && v2 instanceof JamCons) {
    JamCons c1 = (JamCons) v1;
    JamCons c2 = (JamCons) v2;
    return jamValEquals(c1.first(), c2.first()) && jamValEquals(c1.rest(), c2.rest());
  }
  return v1.equals(v2);
}

public JamVal forOpEquals() {
  JamVal v1 = arg1.accept(EvalVisitor.this);
  JamVal v2 = arg2.accept(EvalVisitor.this);
  return BoolConstant.toBoolConstant(jamValEquals(v1, v2));
}

public JamVal forOpNotEquals() {
  JamVal v1 = arg1.accept(EvalVisitor.this);
  JamVal v2 = arg2.accept(EvalVisitor.this);
  return BoolConstant.toBoolConstant(!jamValEquals(v1, v2));
}

