/** A visitor class for the syntax checker. Returns normally unless there is a syntax error. On a syntax error,
  * throws a SyntaxException.
  */
class CheckVisitor implements ASTVisitor<Void> {

  /** Empty symbol table. */
  private static final Empty<Variable> EMPTY_VARS = new Empty<Variable>();

  /** Symbol table to detect free variables. */
  PureList<Variable> env;

  /** Root form of CheckVisitor. */
  public static final CheckVisitor INITIAL = new CheckVisitor(EMPTY_VARS);

  CheckVisitor(PureList<Variable> e) { env = e; }

  /** Returns a new CheckVisitor with the variable added to the env. */
  private CheckVisitor extend(Variable v) {
    return new CheckVisitor(env.cons(v));
  }

  /** Returns a new CheckVisitor with all variables in vars added to the env; also checks for duplicates. */
  private CheckVisitor extend(Variable[] vars) {
    PureList<Variable> newEnv = env;
    PureList<Variable> seen = EMPTY_VARS;
    for (Variable v : vars) {
      if (seen.contains(v)) {
        throw new SyntaxException("Duplicate variable `" + v + "' in binding list");
      }
      seen = seen.cons(v);
      newEnv = newEnv.cons(v);
    }
    return new CheckVisitor(newEnv);
  }

  /* ASTVisitor methods. */

  /** Constants need no checking. */
  public Void forBoolConstant(BoolConstant b) { return null; }

  /** Constants need no checking. */
  public Void forIntConstant(IntConstant i) { return null; }

  /** Constants need no checking. */
  public Void forEmptyConstant(EmptyConstant n) { return null; }

  /** Check that the variable is bound in the current environment. */
  public Void forVariable(Variable v) {
    if (!env.contains(v)) {
      throw new SyntaxException("Free variable `" + v + "' is not bound");
    }
    return null;
  }

  /** Primitive functions are always in scope. */
  public Void forPrimFun(PrimFun f) { return null; }

  /** Check the argument of a unary operator application. */
  public Void forUnOpApp(UnOpApp u) {
    u.arg().accept(this);
    return null;
  }

  /** Check both arguments of a binary operator application. */
  public Void forBinOpApp(BinOpApp b) {
    b.arg1().accept(this);
    b.arg2().accept(this);
    return null;
  }

  /** Check the function and all arguments of an application. */
  public Void forApp(App a) {
    a.rator().accept(this);
    for (AST arg : a.args()) {
      arg.accept(this);
    }
    return null;
  }

  /** Check a map: extend env with params (checking for duplicates) and check the body. */
  public Void forMap(Map m) {
    CheckVisitor extended = extend(m.vars());
    m.body().accept(extended);
    return null;
  }

  /** Check an if expression: check test, consequent, and alternative. */
  public Void forIf(If i) {
    i.test().accept(this);
    i.conseq().accept(this);
    i.alt().accept(this);
    return null;
  }

  /** Check a let: extend env with all bound variables (checking for duplicates), check each RHS and body. */
  public Void forLet(Let l) {
    Variable[] vars = l.vars();
    AST[] exps = l.exps();
    // Check for duplicate names in this let
    CheckVisitor extended = extend(vars);
    // Check each RHS in the extended env (recursive let semantics)
    for (AST exp : exps) {
      exp.accept(extended);
    }
    // Check the body in the extended env
    l.body().accept(extended);
    return null;
  }
}

/** Singleton visitor that checks for duplicate variables in a symbol table. Returns normally unless an error is found.
  * Throws a SyntaxException on error.
  */
class AnyDuplicatesVisitor implements PureListVisitor<Variable, Void> {
  /** Checks an empty list: no duplicates possible. */
  public Void forEmpty(Empty<Variable> e) { return null; }

  /** Checks a non-empty list: verifies the head is not in the tail, then recurses. */
  public Void forCons(Cons<Variable> c) {
    if (c.rest().contains(c.first())) {
      throw new SyntaxException("Duplicate variable `" + c.first() + "' in binding list");
    }
    return c.rest().accept(this);
  }
}

/** Exception type thrown by the context-sensitive checker. */
class SyntaxException extends RuntimeException {
  SyntaxException(String s) { super(s); }
}
